import {
  BnDetectorOptions,
  BnGovernanceDetector,
  BnGovernanceDetectorDef,
  BnGovernanceDetectorId,
  BnGovernanceFinding,
} from '@binom/sdk-governance/types';
import { getAllBuiltinDetectors } from '@binom/sdk-governance/detectors';
import { scanRegex } from '@binom/sdk-governance/detectors';

const registry = new Map<string, BnGovernanceDetector>();

function ensureBuiltins(): void {
  if (registry.size > 0) {
    return;
  }
  for (const detector of getAllBuiltinDetectors()) {
    registry.set(detector.id, detector);
  }
}

export function registerDetector(detector: BnGovernanceDetector): void {
  ensureBuiltins();
  registry.set(detector.id, detector);
}

export function getDetector(id: string): BnGovernanceDetector | undefined {
  ensureBuiltins();
  return registry.get(id);
}

export function getRegisteredDetectors(): BnGovernanceDetector[] {
  ensureBuiltins();
  return Array.from(registry.values());
}

export function createDetector(def: BnGovernanceDetectorDef): BnGovernanceDetector {
  const priority = def.priority ?? 50;
  const confidence = def.confidence ?? 0.75;

  if (def.detect) {
    return {
      id: def.id,
      priority,
      detect: def.detect,
      validate: def.validate,
    };
  }

  if (!def.pattern) {
    throw new Error(`[createDetector] Detector "${def.id}" requires pattern or detect function`);
  }

  const pattern = def.pattern;

  return {
    id: def.id,
    priority,
    validate: def.validate,
    detect: (input: string, options?: BnDetectorOptions): BnGovernanceFinding[] =>
      scanRegex(
        input,
        def.id as BnGovernanceDetectorId,
        pattern,
        confidence,
        def.validate,
        options,
      ),
  };
}

export function resetDetectorRegistry(forTesting = false): void {
  registry.clear();
  if (!forTesting) {
    ensureBuiltins();
  }
}
